UPDATE TB_CM_API_LINK_INFO
SET    ETC03  = #{intgCerTkn}
,      ETC04  = #{intgCerTknPblcDate}
,      ETC05  = #{intgCerTknPblcTime}
,      ETC06  = #{intgCerTknDdlDate}
,      ETC07  = #{intgCerTknDdlTime}
,      MOD_DT = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
,      MOD_ID = #{modId}
WHERE  API_NO = #{apiNo}

