    SELECT SQ_CM_API_LINK.CURRVAL FROM DUAL

INSERT INTO TB_CM_API_LINK
(
       SEQ
   ,   LINK_TYPE
   ,   URL
   ,   REQUEST_METHOD
   ,   REQUEST
   ,   RESPONSE
   ,   REQUEST_DT
   ,   RESPONSE_DT
   ,   STATUS_CODE
   ,   REG_DT
   ,   REG_ID
)
VALUES
(
       SQ_CM_API_LINK.NEXTVAL
   ,   #{linkType}
   ,   #{url}
   ,   #{requestMethod}
   ,   #{request}
   ,   #{response}
   ,   #{requestDt}
   ,   #{responseDt}
   ,   #{statusCode}
   ,   #{regDt}
   ,   #{regId}
)
